 1	import * as React from 'react';
 2	import { FC, ReactNode } from 'react';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { K8sModel } from '@openshift-console/dynamic-plugin-sdk';
 6	import { Button, Grid, Split, SplitItem } from '@patternfly/react-core';
 7	import { ExternalLinkAltIcon, PlusCircleIcon } from '@patternfly/react-icons';
 8	
 9	type LabelsListProps = {
10	  addRowText?: string;
11	  children: ReactNode;
12	  emptyStateAddRowText?: string;
13	  isEmpty: boolean;
14	  model?: K8sModel;
15	  onLabelAdd: () => void;
16	};
17	
18	const LabelsList: FC<LabelsListProps> = ({
19	  addRowText = null,
20	  children,
21	  emptyStateAddRowText = null,
22	  isEmpty,
23	  model,
24	  onLabelAdd,
25	}) => {
26	  const { t } = useKubevirtTranslation();
27	  const addRowTxt = addRowText || t('Add Label');
28	  const emptyStateAddRowTxt = emptyStateAddRowText || t('Add Label to specify qualifying nodes');
29	  return (
30	    <>
31	      <Grid hasGutter>{children}</Grid>
32	      <Split>
33	        <SplitItem>
34	          <Button
35	            className="pf-m-link--align-left"
36	            icon={<PlusCircleIcon />}
37	            id="vm-labels-list-add-btn"
38	            onClick={() => onLabelAdd()}
39	            variant="link"
40	          >
41	            {isEmpty ? emptyStateAddRowTxt : addRowTxt}
42	          </Button>
43	        </SplitItem>
44	        <SplitItem isFilled />
45	        <SplitItem>
46	          {model && (
47	            <Button
48	              className="pf-m-link--align-right"
49	              component="a"
50	              href={`/k8s/cluster/${model.plural}`}
51	              icon={<ExternalLinkAltIcon />}
52	              iconPosition="right"
53	              id="explore-nodes-btn"
54	              target="_blank"
55	              variant="link"
56	            >
57	              {t('Explore {{kind}} list', { kind: model.kind })}
58	            </Button>
59	          )}
60	        </SplitItem>
61	      </Split>
62	    </>
63	  );
64	};
65	
66	export default LabelsList;

